				Description:   tt.newDesc,
				ChangedFields: []string{"description"},
			}
			_, _, _, _, err := validateAndApplyPreClaimIntakeRewrite(original, rewrite)
			require.Error(t, err)
			assert.Contains(t, err.Error(), tt.wantErr)
		})
	}

	var res *ExecuteBeadResult
	select {
	case res = <-done:
	case <-time.After(5 * time.Second):
		t.Fatal("worker did not return within 5s after cancel; mid-attempt poll did not abort")
	}

	if res == nil {
		t.Fatal("nil result")
	}
	if res.Outcome != "preserved" {
		t.Errorf("Outcome = %q, want %q", res.Outcome, "preserved")
